// Generates the Python 3DES demo shown on the Done step.

export function full_script(state) {
  const messageLiteral = JSON.stringify(state.td_message ?? "hello");
  return [
    "# Triple DES — generated by cloak.moosha.org",
    "# Requires the `cryptography` package: pip install cryptography",
    "#",
    "# NOTE: 3DES is officially deprecated by NIST (SP 800-131A, 2023).",
    "# Use AES-GCM for new systems. This demo exists for understanding only.",
    "",
    "import os",
    "from cryptography.hazmat.primitives.ciphers import Cipher, algorithms, modes",
    "from cryptography.hazmat.primitives.padding import PKCS7",
    "",
    "# 3DES key is 24 bytes (three concatenated 8-byte DES keys).",
    "key = os.urandom(24)",
    "iv = os.urandom(8)   # DES block size is 64 bits = 8 bytes",
    "",
    "cipher = Cipher(algorithms.TripleDES(key), modes.CBC(iv))",
    "encryptor = cipher.encryptor()",
    "decryptor = cipher.decryptor()",
    "",
    `message = b${messageLiteral}`,
    "",
    "# PKCS#7 pad to the 8-byte block size",
    "padder = PKCS7(64).padder()",
    "padded = padder.update(message) + padder.finalize()",
    "ciphertext = encryptor.update(padded) + encryptor.finalize()",
    "",
    "# Decrypt to confirm",
    "decrypted_padded = decryptor.update(ciphertext) + decryptor.finalize()",
    "unpadder = PKCS7(64).unpadder()",
    "plaintext = unpadder.update(decrypted_padded) + unpadder.finalize()",
    "assert plaintext == message",
    "",
    `print("key:", key.hex())`,
    `print("iv :", iv.hex())`,
    `print("ct :", ciphertext.hex())`,
    `print("decrypted:", plaintext.decode())`,
  ].join("\n");
}

// Info / non-actionable steps emit nothing for the inline code panel.
export function info(_state) { return ""; }
export function mitm_attack(_state) { return ""; }
export function pick_3des_message(_state) { return ""; }
